    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => doc.data() as DocHistory).sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  },
  getAll: async (): Promise<DocHistory[]> => {
    const q = query(collection(db, "history"), orderBy("timestamp", "desc"));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => doc.data() as DocHistory);
  },
  log: async (docId: string, user: User, action: string, prev: DocState, next: DocState, comment: string, version?: string) => {
    const entryId = `hist-${docId}-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`;
    const newEntry: DocHistory = { 
        id: entryId, 
        documentId: docId, 
        userId: user.id, 
        userName: user.name, 
        action, 
        previousState: prev, 
        newState: next, 
        version: version || '-',
        comment, 
        timestamp: new Date().toISOString() 
    };
    await addDoc(collection(db, "history"), newEntry);
  }
};

export const DocumentService = {
  getAll: async (): Promise<Document[]> => {
    const q = query(collection(db, "documents"), orderBy("updatedAt", "desc"));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Document));
  },
  getById: async (id: string): Promise<Document | null> => {
    const docRef = doc(db, "documents", id);
    const docSnap = await getDoc(docRef);
    return docSnap.exists() ? ({ id: docSnap.id, ...docSnap.data() } as Document) : null;
  },
  create: async (title: string, description: string, author: User, initialState?: DocState, initialVersion?: string, initialProgress?: number, file?: File, hierarchy?: any): Promise<Document> => {
    const state = initialState || DocState.INITIATED;
    const isSubmission = state === DocState.INTERNAL_REVIEW || state === DocState.SENT_TO_REFERENT || state === DocState.SENT_TO_CONTROL;
    let uploadedFiles: DocFile[] = [];
    const mergedAssignees = Array.from(new Set([...(hierarchy?.assignees || []), author.id]));
    const version = initialVersion || '0.0';

    // Si no se provee progreso inicial, lo determinamos por la versión
    const progress = initialProgress !== undefined ? initialProgress : determineStateFromVersion(version).progress;

    const newDocData: Omit<Document, 'id'> = {
      title, description, authorId: author.id, authorName: author.name, assignedTo: author.id, assignees: mergedAssignees, state, version, progress, hasPendingRequest: isSubmission, files: uploadedFiles, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString(), project: hierarchy?.project, macroprocess: hierarchy?.macro, process: hierarchy?.process, microprocess: hierarchy?.micro, docType: hierarchy?.docType
    };
    const docRef = await addDoc(collection(db, "documents"), newDocData);

    await HistoryService.log(docRef.id, author, 'Creación', DocState.NOT_STARTED, state, `Iniciado Versión ${version}`, version);

    const allUsers = await UserService.getAll();
    const coordinators = allUsers.filter(u => u.role === UserRole.COORDINATOR || u.role === UserRole.ADMIN);
    coordinators.forEach(coord => {
        NotificationService.create(
            coord.id,
            docRef.id,
            'ASSIGNMENT',
            'Nueva Solicitud de Documento',
            `El analista ${author.name} ha iniciado: ${title}`,
            author.name
        );
    });

    return { id: docRef.id, ...newDocData } as Document;
  },
  delete: async (id: string) => { await deleteDoc(doc(db, "documents", id)); },
  transitionState: async (docId: string, user: User, action: any, comment: string, file?: File, customVersion?: string): Promise<void> => {
      const docRef = doc(db, "documents", docId);
      const docSnap = await getDoc(docRef);
      if(!docSnap.exists()) throw new Error("Documento no encontrado");
      const currentDoc = docSnap.data() as Document;
      let newState = currentDoc.state;
      let newVersion = currentDoc.version;
      let hasPending = currentDoc.hasPendingRequest;

      const actionLabels: Record<string, string> = {
          'APPROVE': 'Aprobación',
          'REJECT': 'Rechazo',
          'COMMENT': 'Observación',
          'REQUEST_APPROVAL': 'Solicitud de Revisión',
          'ADVANCE': 'Avance de Flujo'
      };

      const displayAction = actionLabels[action] || action;

      if (customVersion) {
        newVersion = customVersion;
        const info = determineStateFromVersion(customVersion);
        newState = info.state;
      }

      if (action === 'APPROVE') hasPending = false;
      else if (action === 'REJECT') { 
          hasPending = false; 
          newState = determineStateFromVersion(newVersion).state; 
      }
      else if (action === 'REQUEST_APPROVAL') hasPending = true;

      // ACTUALIZACIÓN CRÍTICA: Recalcular progreso basado en la nueva versión/estado
      const { progress: newProgress } = determineStateFromVersion(newVersion);

      await updateDoc(docRef, { 
          state: newState, 
          version: newVersion, 
          progress: newProgress, // Sincronizamos el progreso en Firestore
          hasPendingRequest: hasPending, 
          updatedAt: new Date().toISOString() 
      });

      await HistoryService.log(docId, user, displayAction, currentDoc.state, newState, comment, newVersion);

      const allUsers = await UserService.getAll();

      if (action === 'APPROVE' || action === 'REJECT') {
          const notificationType = action === 'APPROVE' ? 'APPROVAL' : 'REJECTION';
          const title = action === 'APPROVE' ? 'Documento Aprobado' : 'Documento Rechazado';
          const msg = `El documento "${currentDoc.title}" ha sido ${action === 'APPROVE' ? 'aprobado' : 'rechazado'} (Versión ${newVersion}).`;

          currentDoc.assignees.forEach(aid => {
              if (aid !== user.id) {
                NotificationService.create(aid, docId, notificationType, title, msg, user.name);
              }
          });

          if (!currentDoc.assignees.includes(currentDoc.authorId) && currentDoc.authorId !== user.id) {
              NotificationService.create(currentDoc.authorId, docId, notificationType, title, msg, user.name);
          }
      } 
      else if (action === 'COMMENT') {
          const msg = `Nueva observación en "${currentDoc.title}": ${comment.substring(0, 50)}...`;
          const targets = new Set([...(currentDoc.assignees || []), currentDoc.authorId]);
          targets.forEach(aid => {
              if (aid !== user.id) {
                NotificationService.create(aid, docId, 'COMMENT', 'Nueva Observación', msg, user.name);
              }
          });
      } 
      else if (customVersion) {
          const reviewStates = [DocState.INTERNAL_REVIEW, DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW, DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW];
          if (reviewStates.includes(newState)) {
              const coordinators = allUsers.filter(u => u.role === UserRole.COORDINATOR || u.role === UserRole.ADMIN);
              const estadoNombre = STATE_CONFIG[newState]?.label.split('(')[0].trim();
              coordinators.forEach(coord => {
                  if (coord.id !== user.id) {
                    NotificationService.create(
                        coord.id,
                        docId,
                        'ASSIGNMENT',
                        'Revisión Solicitada',
                        `Nueva versión en ${estadoNombre}: ${currentDoc.title} (${newVersion})`,
                        user.name
                    );
                  }
              });
          }
      }
  }
};

export const HierarchyService = {
  getFullHierarchy: async (): Promise<FullHierarchy> => {
    const q = query(collection(db, "process_matrix"));
    const snapshot = await getDocs(q);
    const hierarchy: FullHierarchy = {};
    snapshot.docs.forEach(doc => {
      const data = doc.data();
      const proj = data.project;
      const macro = data.macroprocess || 'Sin Macroproceso';
      const process = data.process;
      const node: ProcessNode = { name: data.name, docId: doc.id, assignees: data.assignees || [], referentIds: data.referentIds || [], requiredTypes: data.requiredTypes || [], active: data.active !== false };
      if (!hierarchy[proj]) hierarchy[proj] = {};
      if (!hierarchy[proj][macro]) hierarchy[proj][macro] = {};
      if (!hierarchy[proj][macro][process]) hierarchy[proj][macro][process] = [];
      hierarchy[proj][macro][process].push(node);
    });
    return hierarchy;
  },
  getUserHierarchy: async (userId: string): Promise<UserHierarchy> => {
      const q = query(collection(db, "process_matrix"), where("assignees", "array-contains", userId));
      const snapshot = await getDocs(q);
      const hierarchy: UserHierarchy = {};
      snapshot.docs.forEach(doc => {
          const data = doc.data();
          if (data.active === false) return;
          const proj = data.project;
          const macro = data.macroprocess || 'Sin Macroproceso';
          const process = data.process;
          if (!hierarchy[proj]) hierarchy[proj] = {};
          if (!hierarchy[proj][macro]) hierarchy[proj][macro] = {};
          if (!hierarchy[proj][macro][process]) hierarchy[proj][macro][process] = [];
          hierarchy[proj][macro][process].push(data.name);
      });
      return hierarchy;
  },
  updateMatrixAssignment: async (docId: string, assignees: string[]) => {
      const ref = doc(db, "process_matrix", docId);
      await updateDoc(ref, { assignees });
  },
  updateReferentLinks: async (referentId: string, selectedDocIds: string[]) => {
      const q = query(collection(db, "process_matrix"));
      const snapshot = await getDocs(q);
      const batch = writeBatch(db);

      snapshot.docs.forEach(d => {
          const data = d.data();
          let referents = data.referentIds || [];
          const isSelected = selectedDocIds.includes(d.id);
          const hasReferent = referents.includes(referentId);

          if (isSelected && !hasReferent) {
              batch.update(d.ref, { referentIds: [...referents, referentId] });
          } else if (!isSelected && hasReferent) {
              batch.update(d.ref, { referentIds: referents.filter((id:string) => id !== referentId) });
          }
      });
      await batch.commit();
  },
  toggleRequiredType: async (docId: string, type: DocType) => {
      const ref = doc(db, "process_matrix", docId);
      const snap = await getDoc(ref);
      if (snap.exists()) {
          const current = new Set(snap.data().requiredTypes || []);
          if (current.has(type)) current.delete(type); else current.add(type);
          await updateDoc(ref, { requiredTypes: Array.from(current) });
      }
  },
  addMicroprocess: async (project: string, macro: string, process: string, name: string, assignees: string[], requiredTypes: string[]) => {
      const id = generateMatrixId(project, name);
      await setDoc(doc(db, "process_matrix", id), { project, macroprocess: macro, process, name, assignees, referentIds: [], requiredTypes, active: true });
  },
  deleteMicroprocess: async (docId: string) => { await deleteDoc(doc(db, "process_matrix", docId)); },
  getRequiredTypesMap: async (): Promise<Record<string, DocType[]>> => {
      const q = query(collection(db, "process_matrix"));
      const snapshot = await getDocs(q);
      const map: Record<string, DocType[]> = {};
      snapshot.docs.forEach(d => {
          const data = d.data();
          const key = `${normalizeHeader(data.project)}|${normalizeHeader(data.name)}`;
          map[key] = data.requiredTypes || [];
      });
      return map;
  },
  toggleProcessStatus: async (docId: string, currentStatus: boolean) => {
      const ref = doc(db, "process_matrix", docId);
      await updateDoc(ref, { active: !currentStatus });
  },
  deleteHierarchyNode: async (level: 'PROJECT' | 'MACRO' | 'PROCESS', name: string, context: { project?: string, macro?: string }) => {
      let q;
      if (level === 'PROJECT') {
          q = query(collection(db, "process_matrix"), where("project", "==", name));
      } else if (level === 'MACRO') {
          q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", name));
      } else { // PROCESS
          q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", context.macro), where("process", "==", name));
      }

      const snapshot = await getDocs(q);
      const batch = writeBatch(db);
      snapshot.docs.forEach(d => batch.delete(d.ref));
      await batch.commit();
  },
  updateHierarchyNode: async (level: 'PROJECT' | 'MACRO' | 'PROCESS', oldName: string, newName: string, context: { project?: string, macro?: string }) => {
      let q;
      if (level === 'PROJECT') {
          q = query(collection(db, "process_matrix"), where("project", "==", oldName));
      } else if (level === 'MACRO') {
          q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", oldName));
      } else { // PROCESS
          q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", context.macro), where("process", "==", oldName));
      }
      const snapshot = await getDocs(q);
      const batch = writeBatch(db);
      snapshot.docs.forEach(d => {
          const update: any = {};
          if (level === 'PROJECT') update.project = newName;
          else if (level === 'MACRO') update.macroprocess = newName;
          else update.process = newName;
          batch.update(d.ref, update);
      });
      await batch.commit();
  },
  moveMicroprocess: async (docId: string, targetProject: string, targetMacro: string, targetProcess: string) => {
      const ref = doc(db, "process_matrix", docId);
      await updateDoc(ref, {
          project: targetProject,
          macroprocess: targetMacro,
          process: targetProcess
      });
  },
  seedDefaults: async () => {
      const batch = writeBatch(db);
      for (const row of REQUIRED_DOCS_MATRIX) {
           const [project, micro, asis, fce, pm, tobe] = row;
           const requiredTypes: string[] = [];
           if (asis) requiredTypes.push('AS IS'); if (fce) requiredTypes.push('FCE'); if (pm) requiredTypes.push('PM'); if (tobe) requiredTypes.push('TO BE');
           const id = generateMatrixId(project, micro);
           batch.set(doc(db, "process_matrix", id), { project, macroprocess: 'Macroproceso General', process: 'Proceso General', name: micro, assignees: [], referentIds: [], requiredTypes, active: true });
      }
      await batch.commit();
  }
};

export const DatabaseService = {
    exportData: async (): Promise<string> => {
        const collections = ['users', 'documents', 'history', 'process_matrix', 'notifications', 'referents'];
        const data: any = {};
        for (const colName of collections) {
            const snapshot = await getDocs(collection(db, colName));
            data[colName] = snapshot.docs.map(d => ({ _id: d.id, ...d.data() }));
        }
        return JSON.stringify(data, null, 2);
    },
    importData: async (jsonString: string) => {
        const data = JSON.parse(jsonString);
        for (const colName of Object.keys(data)) {
            await deleteCollectionInBatches(colName);
            const items = data[colName];
            let batch = writeBatch(db);
            let count = 0;
            for (const item of items) {
                const { _id, ...docData } = item;
                batch.set(doc(db, colName, _id), docData);
                count++;
                if (count >= 400) { await batch.commit(); batch = writeBatch(db); count = 0; }
            }
            if (count > 0) await batch.commit();
        }
    },
    fullSystemResetAndImport: async (rulesCSV: string, historyCSV: string, onProgress: (percent: number, status: string) => void): Promise<{ created: number, historyMatched: number }> => {
        onProgress(5, "Limpiando...");
        await deleteCollectionInBatches("documents"); await deleteCollectionInBatches("history"); await deleteCollectionInBatches("process_matrix"); await deleteCollectionInBatches("notifications");
        onProgress(10, "Reglas...");
        const rows = rulesCSV.split(/\r?\n/).filter(r => r.trim().length > 0);
        const headers = rows[0].split(/[;,]/).map(h => normalizeHeader(h));
        const idxProject = headers.findIndex(h => h.includes('PROYECTO'));
        const idxMacro = headers.findIndex(h => h.includes('MACRO'));
        const idxProcess = headers.findIndex(h => h === 'PROCESO');
        const idxMicro = headers.findIndex(h => h.includes('MICRO'));
        const idxAnalyst = headers.findIndex(h => h.includes('ANALISTA') || h.includes('RESPONSABLE'));
        const idxAsis = headers.findIndex(h => h.includes('ASIS') || h.includes('AS IS'));
        const idxFce = headers.findIndex(h => h.includes('FCE'));
        const idxPm = headers.findIndex(h => h.includes('PM'));
        const idxTobe = headers.findIndex(h => h.includes('TOBE') || h.includes('TO BE'));
        const allUsers = await UserService.getAll();
        let createdCount = 0;
        let batch = writeBatch(db);
        let opCount = 0;
        for (let i = 1; i < rows.length; i++) {
            const cols = rows[i].split(/[;,]/).map(c => c.trim());
            if (cols.length < 3) continue;
            const project = cols[idxProject] || 'GENERAL';
            const macro = cols[idxMacro] || 'General';
            const process = cols[idxProcess] || 'General';
            const micro = cols[idxMicro];
            if (!micro) continue;
            const assignees = findUserIdsFromCSV(allUsers, cols[idxAnalyst]);
            const requiredTypes: string[] = [];
            if (cols[idxAsis] === '1') requiredTypes.push('AS IS');
            if (cols[idxFce] === '1') requiredTypes.push('FCE');
            if (cols[idxPm] === '1') requiredTypes.push('PM');
            if (cols[idxTobe] === '1') requiredTypes.push('TO BE');
            const id = generateMatrixId(project, micro);
            const nodeData = { project, macroprocess: macro, process, name: micro, assignees, referentIds: [], requiredTypes, active: true };
            batch.set(doc(db, "process_matrix", id), nodeData);
            opCount++; createdCount++;
            if (opCount >= 400) { await batch.commit(); batch = writeBatch(db); opCount = 0; }
        }
        if (opCount > 0) await batch.commit();
        onProgress(100, "Finalizando...");
        return { created: createdCount, historyMatched: 0 };
    }
};

import { ParsedFilenameResult } from '../types';
import { DocState } from '../types';

export const parseDocumentFilename = (
  fullFilename: string, 
  expectedProject?: string,
  expectedMicro?: string,
  expectedType?: string,
  expectedRequestType?: 'INITIATED' | 'IN_PROCESS' | 'INTERNAL' | 'REFERENT' | 'CONTROL'
): ParsedFilenameResult => {
  const result: ParsedFilenameResult = {
    valido: false,
    errores: []
  };

  const lastDotIndex = fullFilename.lastIndexOf('.');
  const filenameBase = lastDotIndex !== -1 ? fullFilename.substring(0, lastDotIndex) : fullFilename;

  if (filenameBase.length > 80) {
    result.errores.push(`El nombre del archivo excede 80 caracteres.`);
  }

  const parts = filenameBase.split(' - ');

  if (parts.length < 4) {
    result.errores.push('Formato incorrecto. Use: "PROYECTO - Microproceso - TIPO - Versión".');
    return result;
  }

  const proyecto = parts[0];
  const version = parts[parts.length - 1];
  const tipoCodigo = parts[parts.length - 2];
  const microproceso = parts.slice(1, parts.length - 2).join(' - ');

  if (proyecto !== 'HPC' && proyecto !== 'HSR') {
    result.errores.push(`Proyecto inválido: ${proyecto}.`);
  } else if (expectedProject && proyecto !== expectedProject) {
    result.errores.push(`Proyecto no coincide con la solicitud.`);
  }
  result.proyecto = proyecto as 'HPC' | 'HSR';

  if (!microproceso || microproceso.trim() === '') {
    result.errores.push('Microproceso vacío.');
  } else if (expectedMicro && microproceso !== expectedMicro) {
    result.errores.push(`Microproceso no coincide.`);
  }
  result.microproceso = microproceso;

  const mapTypeToCode: Record<string, string> = {
      'AS IS': 'ASIS', 'TO BE': 'TOBE', 'FCE': 'FCE', 'PM': 'PM'
  };
  const validCodes = Object.values(mapTypeToCode);
  if (!validCodes.includes(tipoCodigo)) {
      result.errores.push(`Tipo inválido: ${tipoCodigo}.`);
  }
  if (expectedType) {
      const expectedCode = mapTypeToCode[expectedType];
      if (tipoCodigo !== expectedCode) {
          result.errores.push(`Tipo no coincide con la solicitud.`);
      }
  }
  result.tipo = tipoCodigo;

  result.nomenclatura = version;

  const regexInitiated = /^0\.0$/;              
  const regexInProcess = /^0\.(\d+)$/;          
  const regexInternal = /^v0\.(\d+)$/;          
  const regexReferent = /^v1\.(\d+)\.(\d+)$/;   
  const regexControl = /^v1\.(\d+)\.(\d+)AR$/;  
  const regexStandard = /^v?\d+(\.\d+)*([A-Z]+)?$/;

  if (expectedRequestType) {
      if (expectedRequestType === 'INITIATED') {
          if (!regexInitiated.test(version)) {
              result.errores.push('Para estado "Iniciado" la versión debe ser estrictamente "0.0".');
          }
      } else if (expectedRequestType === 'IN_PROCESS') {
          const match = version.match(regexInProcess);
          if (!match) {
              result.errores.push('Para "En Proceso" el formato debe ser "0.n" (ej: 0.1, 0.2) sin la letra "v".');
          } else {
               const n = parseInt(match[1]);
               if (n === 0) {
                   result.errores.push('La versión 0.0 corresponde a "Iniciado". Para "En Proceso" n debe ser mayor a 0 (ej: 0.1).');
               }
          }
      } else if (expectedRequestType === 'INTERNAL') {
          const match = version.match(regexInternal);
          if (!match) {
              result.errores.push('Para Revisión Interna el formato debe ser "v0.n" (con v).');
          } else {
              const n = parseInt(match[1]);
              if (n % 2 === 0) {
                  result.errores.push(`Para Revisión Interna el dígito "n" (${n}) debe ser IMPAR (ej: v0.1, v0.3).`);
              }
          }
      } else if (expectedRequestType === 'REFERENT') {
          const match = version.match(regexReferent);
          if (!match) {
              result.errores.push('Para Revisión Interna Referente el formato debe ser "v1.n.i" (ej: v1.0.1).');
          } else {
              const i = parseInt(match[2]);
              if (i % 2 === 0) {
                  result.errores.push(`Para Revisión Interna Referente el dígito "i" (${i}) debe ser IMPAR (ej: v1.0.1, v1.0.3).`);
              }
          }
      } else if (expectedRequestType === 'CONTROL') {
          const match = version.match(regexControl);
          if (!match) {
              result.errores.push('Para Revisión Interna Control el formato debe ser "v1.n.iAR" (ej: v1.0.1AR).');
          } else {
              const i = parseInt(match[2]);
              if (i % 2 === 0) {
                  result.errores.push(`Para Revisión Interna Control el dígito "i" (${i}) debe ser IMPAR (ej: v1.0.1AR).`);
              }
          }
      }
  }

  if (result.errores.length === 0) {
      const vUpper = version.toUpperCase();

      // REGLAS DE PORCENTAJE CENTRALIZADAS
      if (vUpper.endsWith('ACG')) {
          result.estado = 'Aprobado';
          result.porcentaje = 100;
      } else if (vUpper.endsWith('AR')) {
          // Control de Gestión
          result.estado = vUpper.match(/^V1\.\d+\.\d+AR$/) ? 'Revisión Interna Control' : 'Enviado a Control de Gestión';
          result.porcentaje = 90;
      } else if (vUpper.startsWith('V1.')) {
          // Referentes
          result.estado = vUpper.split('.').length > 2 ? 'Revisión Interna Referente' : 'Enviado a Referente';
          result.porcentaje = 80;
      } else if (vUpper.startsWith('V0.')) {
          // Revisión Interna Analítica
          result.estado = 'En revisión interna'; 
          result.porcentaje = 60;
      } else if (version === '0.0') {
          result.estado = 'Iniciado';
          result.porcentaje = 10;
      } else if (/^0\.\d+$/.test(version)) {
          result.estado = 'En Proceso';
          result.porcentaje = 30;
      } else {
          result.estado = 'En Proceso'; 
          result.porcentaje = 30;
      }
  }

  result.valido = result.errores.length === 0;
  return result;
};

export const validateCoordinatorRules = (
    filename: string,
    currentVersion: string, 
    currentState: DocState,
    action: 'APPROVE' | 'REJECT'
): { valid: boolean; error?: string; hint?: string } => {

    const parts = filename.replace(/\.[^/.]+$/, "").split(' - ');
    if (parts.length < 4) return { valid: false, error: 'Formato de nombre inválido.' };
    const newVersion = parts[parts.length - 1];

    const getParts = (v: string) => {
        let m;
        m = v.match(/^v?0\.(\d+)$/);
        if (m) return { n: parseInt(m[1]), i: null, ar: false, acg: false, type: 'v0.n' };
        m = v.match(/^v1\.(\d+)$/);
        if (m) return { n: parseInt(m[1]), i: null, ar: false, acg: false, type: 'v1.n' };
        m = v.match(/^v1\.(\d+)\.(\d+)$/);
        if (m) return { n: parseInt(m[1]), i: parseInt(m[2]), ar: false, acg: false, type: 'v1.n.i' };
        m = v.match(/^v1\.(\d+)\.(\d+)AR$/);
        if (m) return { n: parseInt(m[1]), i: parseInt(m[2]), ar: true, acg: false, type: 'v1.n.iAR' };
        m = v.match(/^v1\.(\d+)AR$/);
        if (m) return { n: parseInt(m[1]), i: null, ar: true, acg: false, type: 'v1.nAR' };
        m = v.match(/^v1\.(\d+)ACG$/);
        if (m) return { n: parseInt(m[1]), i: null, ar: false, acg: true, type: 'v1.nACG' };
        return null;
    };

    const current = getParts(currentVersion);
    const incoming = getParts(newVersion);

    if (!incoming) return { valid: false, error: 'Formato de versión no reconocido.' };

    if (currentState === DocState.INTERNAL_REVIEW) {
        if (action === 'APPROVE') {
            if (incoming.type !== 'v1.n') return { valid: false, error: 'Aprobación requiere v1.n (Ej: v1.0).' };
            return { valid: true };
        } else {
            if (incoming.type !== 'v0.n') return { valid: false, error: 'Rechazo requiere v0.n.' };
            if (incoming.n % 2 !== 0) return { valid: false, error: `Para rechazar, "n" (${incoming.n}) debe ser PAR (ej: v0.2, v0.4).` };
            return { valid: true };
        }
    }

    if (currentState === DocState.SENT_TO_REFERENT || currentState === DocState.REFERENT_REVIEW) {
        if (action === 'APPROVE') {
            if (incoming.type === 'v1.n') {
                if (current && incoming.n <= current.n) return { valid: false, error: `Para consolidar versión, v1.${incoming.n} debe ser mayor a la actual (v1.${current.n}...).` };
                return { valid: true };
            } else if (incoming.type === 'v1.nAR') {
                if (current?.type === 'v1.n.i') {
                    if (incoming.n <= current.n) return { valid: false, error: `Al aprobar borrador para Control, debe consolidar versión (v1.${current.n + 1}AR).` };
                    return { valid: true };
                }
                if (current?.type === 'v1.n') {
                    if (incoming.n !== current.n) return { valid: false, error: `Al aprobar versión limpia para Control, mantenga el número (v1.${current.n}AR).` };
                    return { valid: true };
                }
                if (current && incoming.n < current.n) return { valid: false, error: 'No puede bajar de versión.' };
                return { valid: true };
            } else {
                return { valid: false, error: 'Aprobación requiere v1.n (Consolidar) o v1.nAR (Control).' };
            }
        } else {
            if (incoming.type !== 'v1.n.i') return { valid: false, error: 'Rechazo requiere v1.n.i (Ej: v1.0.2).' };
            if (incoming.i! % 2 !== 0) return { valid: false, error: `Para rechazar, el último dígito "i" (${incoming.i}) debe ser PAR.` };
            if (current && incoming.n !== current.n) return { valid: false, error: `El rechazo debe mantener la versión base v1.${current.n}.` };
            if (current?.i !== null && incoming.i! <= current!.i!) return { valid: false, error: `El dígito "i" (${incoming.i}) debe ser mayor al actual.` };
            return { valid: true };
        }
    }

    if (currentState === DocState.SENT_TO_CONTROL || currentState === DocState.CONTROL_REVIEW) {
        if (action === 'APPROVE') {
            if (incoming.type === 'v1.nAR') {
                if (current && incoming.n <= current.n) return { valid: false, error: `Para avanzar versión, v1.${incoming.n}AR debe ser mayor a la actual (v1.${current.n}...).` };
                return { valid: true };
            }
            if (incoming.type === 'v1.nACG') {
                return { valid: true };
            }
            return { valid: false, error: 'Aprobación requiere v1.nAR (avance) o v1.nACG (final).' };
        } else {
            if (incoming.type !== 'v1.n.iAR') return { valid: false, error: 'Rechazo requiere v1.n.iAR (Ej: v1.0.2AR).' };
            if (incoming.i! % 2 !== 0) return { valid: false, error: `Para rechazar, el dígito "i" (${incoming.i}) debe ser PAR.` };
            if (current && current.type === 'v1.n.iAR') {
                 if (incoming.i! <= current.i!) return { valid: false, error: `El dígito "i" (${incoming.i}) debe ser mayor al actual (${current.i}).` };
            }
            return { valid: true };
        }
    }

    return { valid: true };
}

export const getCoordinatorRuleHint = (currentState: DocState, action: 'APPROVE' | 'REJECT'): string => {
    if (action === 'REJECT') {
        if (currentState === DocState.INTERNAL_REVIEW) return 'Formato: v0.n (n PAR). Ej: v0.2';
        if (currentState === DocState.SENT_TO_REFERENT || currentState === DocState.REFERENT_REVIEW) return 'Formato: v1.n.i (i PAR). Ej: v1.0.2';
        if (currentState === DocState.SENT_TO_CONTROL || currentState === DocState.CONTROL_REVIEW) return 'Formato: v1.n.iAR (i PAR y mayor). Ej: v1.0.2AR';
    } else {
        if (currentState === DocState.INTERNAL_REVIEW) return 'Formato: v1.n (Ej: v1.0)';
        if (currentState === DocState.SENT_TO_REFERENT || currentState === DocState.REFERENT_REVIEW) {
            return 'Opción 1: v1.n (Consolidar) / Opción 2: v1.nAR (Enviar a Control)';
        }
        if (currentState === DocState.SENT_TO_CONTROL || currentState === DocState.CONTROL_REVIEW) return 'Opción 1: v1.nAR (Avance) / Opción 2: v1.nACG (Final)';
    }
    return 'Formato estándar';
};

