import React, { useState } from 'react';
import { loginUser, registerUser } from '../services/firebaseAuthService'; 
import { UserService } from '../services/firebaseBackend';
import { MOCK_USERS } from '../constants';
import { User as UserType } from '../types';
import { Lock, User, Key, AlertCircle, TrendingUp, Mail, UserPlus, LogIn, ChevronDown } from 'lucide-react'; 
import { useNavigate } from 'react-router-dom'; 
import { auth } from '../services/firebaseConfig'; 
import { GoogleAuthProvider, signInWithPopup } from 'firebase/auth'; 

const Login: React.FC = () => {
    const [isRegistering, setIsRegistering] = useState(false);
    const [showEmailFields, setShowEmailFields] = useState(false);
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError(''); setLoading(true);
        try {
            if (isRegistering) { 
                await registerUser(email, password, name); 
                navigate('/'); 
            } else { 
                await loginUser(email, password); 
                navigate('/'); 
            }
        } catch (err: any) {
            if (!isRegistering) {
                 let target: UserType | undefined = MOCK_USERS.find(u => u.email === email && u.password === password);
                 if (!target) { 
                    try { 
                        const all = await UserService.getAll(); 
                        target = all.find(u => u.email === email && u.password === password); 
                    } catch(e){} 
                 }
                 if (target) { 
                    localStorage.setItem('sgd_user_cache', JSON.stringify(target)); 
                    window.location.reload(); 
                    return; 
                 }
            }
            setError(err.message || 'Error de autenticación'); 
            setLoading(false);
        }
    };

    const handleGoogleSignIn = async () => {
        setLoading(true);
        setError('');
        try { 
            await signInWithPopup(auth, new GoogleAuthProvider()); 
            navigate('/'); 
        } catch (err: any) { 
            setError("Error al iniciar sesión con Google"); 
            setLoading(false); 
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-[#f1f5f9] p-4">
            <div className="bg-white p-10 rounded-[24px] shadow-[0_10px_40px_-15px_rgba(0,0,0,0.1)] w-full max-w-sm border border-slate-100 flex flex-col items-center">

                {/* Header Section */}
                <div className="text-center mb-10">
                    <h1 className="text-[40px] font-black text-[#1e293b] leading-tight mb-1">SGD</h1>
                    <p className="text-slate-500 text-lg font-medium">Gestión Documental</p>
                </div>

                <div className="w-full space-y-6">
                    {/* Primary Option: Google */}
                    <button 
                        type="button" 
                        onClick={handleGoogleSignIn} 
                        disabled={loading} 
                        className="w-full bg-white border border-slate-200 py-4 rounded-xl shadow-sm font-bold flex items-center justify-center gap-3 hover:bg-slate-50 transition-all active:scale-[0.98] disabled:opacity-50"
                    >
                        {/* Custom Google Icon mimic from image */}
                        <div className="w-5 h-5 flex items-center justify-center">
                            <TrendingUp size={20} className="text-[#ea4335]" />
                        </div>
                        <span className="text-lg text-[#1e293b]">Google</span>
                    </button>

                    {/* Expandable Divider Indicator */}
                    <div className="relative py-4 flex items-center justify-center group cursor-pointer" onClick={() => setShowEmailFields(!showEmailFields)}>
                        <div className="w-full border-t border-[#4f46e5]"></div>
                        <div className="absolute right-0 top-1/2 -translate-y-1/2">
                            <div className="w-0 h-0 border-l-[12px] border-l-transparent border-r-[12px] border-r-transparent border-t-[16px] border-t-[#3b82f6] shadow-sm transform transition-transform duration-300" 
                                 style={{ transform: showEmailFields ? 'translateY(-20%) rotate(180deg)' : 'translateY(-20%)' }}>
                            </div>
                        </div>
                    </div>

                    {/* Collapsible Email Form */}
                    <div className={`space-y-4 overflow-hidden transition-all duration-500 ease-in-out ${showEmailFields ? 'max-h-[500px] opacity-100 mb-4' : 'max-h-0 opacity-0'}`}>
                        <form onSubmit={handleSubmit} className="space-y-4">
                            {isRegistering && (
                                <div className="relative">
                                    <User className="absolute left-4 top-3.5 text-slate-400" size={18}/>
                                    <input 
                                        placeholder="Nombre" 
                                        value={name} 
                                        onChange={(e) => setName(e.target.value)} 
                                        className="w-full pl-12 pr-4 py-3.5 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" 
                                        required={isRegistering} 
                                    />
                                </div>
                            )}

                            <div className="relative">
                                <Mail className="absolute left-4 top-3.5 text-slate-400" size={18}/>
                                <input 
                                    type="email" 
                                    placeholder="Email" 
                                    value={email} 
                                    onChange={(e) => setEmail(e.target.value)} 
                                    className="w-full pl-12 pr-4 py-3.5 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" 
                                    required={showEmailFields} 
                                />
                            </div>

                            <div className="relative">
                                <Lock className="absolute left-4 top-3.5 text-slate-400" size={18}/>
                                <input 
                                    type="password" 
                                    placeholder="Contraseña" 
                                    value={password} 
                                    onChange={(e) => setPassword(e.target.value)} 
                                    className="w-full pl-12 pr-4 py-3.5 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 transition-all" 
                                    required={showEmailFields} 
                                />
                            </div>

                            {error && <p className="text-xs text-red-600 bg-red-50 p-3 rounded-lg border border-red-100 flex items-center gap-2"><AlertCircle size={14}/> {error}</p>}

                            <button 
                                type="submit" 
                                disabled={loading} 
                                className="w-full bg-[#4f46e5] text-white py-4 rounded-xl font-bold text-lg shadow-[0_4px_15px_-5px_rgba(79,70,229,0.5)] hover:bg-[#4338ca] transition-all active:scale-[0.98] disabled:opacity-70 mt-2"
                            >
                                {loading ? '...' : (isRegistering ? 'Crear Cuenta' : 'Entrar')}
                            </button>

                            <div className="flex justify-center pt-2">
                                <button 
                                    type="button" 
                                    onClick={() => setIsRegistering(!isRegistering)} 
                                    className="text-xs font-semibold text-indigo-600 hover:text-indigo-800 transition-colors uppercase tracking-wider"
                                >
                                    {isRegistering ? 'Volver al Login' : '¿No tienes cuenta? Regístrate'}
                                </button>
                            </div>
                        </form>
                    </div>

                    {!showEmailFields && (
                        <div className="text-center">
                            <button 
                                onClick={() => setShowEmailFields(true)}
                                className="text-slate-400 text-sm font-medium hover:text-slate-600 transition-colors flex items-center justify-center gap-2 mx-auto"
                            >
                                Ingresar con Email y Contraseña <ChevronDown size={14} />
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

